# Exemplo de repetição
for i in range(3):
    print('Calculando...')

# Usando if, elif e else
x = 42
if x < 0:
    print('Negativo')
elif x == 0:
    print('Zero')
else:
    print('Positivo')

# Usando range()
for i in range(3):
    print(i)  # Imprime: 0, 1, 2

for n in range(2, 4):
    for x in range(2, n):
        if n % x == 0:
            print(n, 'não é primo')
            break
    else:
        # Executado se o loop interno terminar sem quebrar
        print(n, 'é um número primo')

frutas = ['Maca', 'Banana', 'Laranja']
busca = 'Uva'

for fruta in frutas:
    if fruta == busca:
        print('Encontrei a fruta!')
        break
else:
    # Roda se o break nunca foi atingido!
    print('Não tínhamos essa fruta na lista.')
